// test/vectors/slhdsa_siggen.ts
//
// NIST ACVP SLH-DSA-sigGen test vectors (FIPS 205).
//
// Source:
//   ACVP-Server/gen-val/json-files/SLH-DSA-sigGen-FIPS205/internalProjection.json
//   @see https://github.com/usnistgov/ACVP-Server/tree/master/gen-val/json-files/SLH-DSA-sigGen-FIPS205
//   pin: 15c0f3deeefbfa8cb6cd32a99e1ca3b738c66bf0 (v1.1.0.42, 2026-04-16)
//   vsId=53, algorithm=SLH-DSA, mode=sigGen, revision=FIPS205, isSample=true
//
// Curated SHAKE-fast subset.
// HashSLH-DSA prehash cases are merged into the same JSON via a
// per-group `preHash` discriminator (none / pure / preHash); we carry
// both pure (external SLH-DSA.Sign per §10.1) and preHash (HashSLH-DSA
// per §10.2) curated subsets here. `deterministic=true` implies
// opt_rand = PK.seed (FIPS 205 §3.4); otherwise `additionalRandomness`
// carries the lib-supplied opt_rand the signer used.
//
// Per parameter set: 5 pure-det + 5 pure-hedged + 3 preHash-det = 13.
// Total: 39 across 128f/192f/256f.

export type ParameterSet = 'SLH-DSA-SHAKE-128f' | 'SLH-DSA-SHAKE-192f' | 'SLH-DSA-SHAKE-256f';
export type SignatureInterface = 'external';
export type PreHash = 'pure' | 'preHash';

export interface SigGenVector {
	tcId:                 number;
	tgId:                 number;
	parameterSet:         ParameterSet;
	signatureInterface:   SignatureInterface;
	preHash:              PreHash;
	deterministic:        boolean;
	hashAlg:              string; // 'none' for pure mode, e.g. 'SHA2-512/224' for preHash
	sk:                   string;
	pk:                   string;
	message:              string;
	context:              string;
	additionalRandomness?: string; // present when deterministic=false; n bytes
	signature:            string;
}

